    27→export const handler = async (event) => {
    28→  const headers = { 'Content-Type': 'application/json', ...corsHeaders(event) };
    29→
    30→  // CORS pre-flight
    31→  if (event.httpMethod === 'OPTIONS') return { statusCode: 204, headers, body: '' };
    32→  if (event.httpMethod !== 'POST')    return { statusCode: 405, headers, body: JSON.stringify({ error: 'Method not allowed' }) };
    33→
