    35→  let body;
    36→  try { body = JSON.parse(event.body || '{}'); }
    37→  catch { return { statusCode: 400, headers, body: JSON.stringify({ error: 'Invalid JSON body' }) }; }
    38→
    39→  const email    = sanitizeString(body.email, 254);
    40→  const userName = sanitizeString(body.userName, 100);
    41→
    42→  if (!email || !validateEmail(email)) {
    43→    return { statusCode: 400, headers, body: JSON.stringify({ error: 'A valid email address is required' }) };
    44→  }
    45→
    46→  // Rate limit: 3 attempts per 5 minutes per IP
    47→  const clientIp = event.headers['x-forwarded-for']?.split(',')[0]?.trim() || 'unknown';
    48→  const rl = rateLimitCheck(`reset:${clientIp}`, 3, 5 * 60 * 1000);
    49→  if (!rl.ok) {
    50→    log.warn('Rate limited - password reset', { ip: clientIp });
    51→    return {
    52→      statusCode: 429,
    53→      headers: { ...headers, 'Retry-After': String(rl.retryAfter) },
    54→      body: JSON.stringify({ error: 'Too many requests. Please wait a few minutes before trying again.' }),
    55→    };
    56→  }
    57→
    58→  // Generate Firebase action link (Admin SDK — no email sent by Firebase)
    59→  const actionCodeSettings = {
    60→    url:              'https://tingletap.com/reset-password',
    61→    handleCodeInApp:  false,
