    96→      .replace(/\{\{user_email\}\}/g, email)
    97→      .replace(/\{\{reset_link\}\}/g, customResetUrl);
    98→  } catch (err) {
    99→    log.error('PasswordReset template load failed', { message: err.message });
   100→    return { statusCode: 500, headers, body: JSON.stringify({ error: 'Email template error' }) };
   101→  }
   102→
   103→  // Send via Brevo
   104→  try {
