     1→// Brevo transactional email service for Netlify Functions
     2→// Env var: BREVO_API_KEY
     3→const BREVO_ENDPOINT = 'https://api.brevo.com/v3/smtp/email';
     4→const DEFAULT_SENDER = { name: 'TingleTap', email: 'alerts@tingletap.com' };
     5→
     6→/**
     7→ * Send a transactional email via Brevo REST API.
     8→ * @param {object} opts
     9→ * @param {Array<{email:string,name?:string}>} opts.to
    10→ * @param {string}  opts.subject
    11→ * @param {string}  opts.htmlContent
    12→ * @param {string}  opts.textContent
    13→ * @param {object}  [opts.sender]        - overrides DEFAULT_SENDER
    14→ * @param {object}  [opts.replyTo]
    15→ * @param {Array}   [opts.tags]
    16→ */
    17→export async function sendEmailWithTemplate({ to, subject, htmlContent, textContent, sender, replyTo, tags = [] }) {
    18→  const apiKey = process.env.BREVO_API_KEY;
    19→  if (!apiKey) throw new Error('[emailService] BREVO_API_KEY not set');
    20→
    21→  const payload = {
    22→    sender:      sender  || DEFAULT_SENDER,
    23→    to,
    24→    subject,
    25→    htmlContent,
    26→    textContent,
    27→    tags: ['tingletap-transactional', ...tags],
    28→  };
    29→  if (replyTo) payload.replyTo = replyTo;
    30→
    31→  const res = await fetch(BREVO_ENDPOINT, {
    32→    method: 'POST',
    33→    headers: { 'api-key': apiKey, 'content-type': 'application/json' },
    34→    body: JSON.stringify(payload),
    35→  });
    36→
    37→  if (!res.ok) {
    38→    const err = await res.json().catch(() => ({}));
    39→    throw new Error(`Brevo API error ${res.status}: ${err.message || JSON.stringify(err)}`);
    40→  }
    41→
    42→  return res.json();
    43→}
