     1→// Lazy-loading, in-memory cached HTML template loader for Netlify Functions
     2→import { readFile } from 'fs/promises';
     3→import { fileURLToPath } from 'url';
     4→import { join, dirname } from 'path';
     5→
     6→const __dirname = dirname(fileURLToPath(import.meta.url));
     7→// Netlify Functions run from repo root, so Templates/ is 3 levels up from shared/
     8→const TEMPLATES_DIR = join(__dirname, '..', '..', '..', 'Templates');
     9→
    10→// Simple in-memory cache — functions warm up quickly, reuse across invocations
    11→const cache = new Map();
    12→
    13→/**
    14→ * Load an HTML template file and return its content.
    15→ * Templates are cached after first load.
    16→ * @param {string} filename  e.g. 'PasswordReset.html'
    17→ * @returns {Promise<string>} raw HTML string
    18→ */
    19→export async function loadTemplate(filename) {
    20→  if (cache.has(filename)) return cache.get(filename);
    21→
    22→  const filePath = join(TEMPLATES_DIR, filename);
    23→  const content  = await readFile(filePath, 'utf8');
    24→  cache.set(filename, content);
    25→  return content;
    26→}
    27→
    28→/**
    29→ * Clear template cache (useful for testing).
    30→ */
    31→export function clearCache() {
    32→  cache.clear();
    33→}
