    20→// ── JWT decode (no signature verify — Firestore REST call does that) ──────────
    21→function decodeJwt(token) {
    22→  try {
    23→    const b64 = token.split('.')[1];
    24→    return JSON.parse(Buffer.from(b64, 'base64url').toString('utf8'));
    25→  } catch { return null; }
    26→}
