    28→// ── Verify Firebase ID token + check role=owner via Firestore REST ─────────────
    29→async function verifyOwner(token) {
    30→  const p = decodeJwt(token);
    31→  if (!p) return { ok: false, err: 'Invalid token format' };
    32→
    33→  const uid = p.user_id || p.sub;
    34→  if (!uid)  return { ok: false, err: 'Token missing UID' };
    35→  if (p.exp && Date.now() / 1000 > p.exp) return { ok: false, err: 'Token expired' };
    36→  if (p.aud !== FIREBASE_PROJECT_ID) return { ok: false, err: 'Token audience mismatch' };
    37→
    38→  // Firestore REST — token verification is implicit (401 if invalid)
    39→  const url = `https://firestore.googleapis.com/v1/projects/${FIREBASE_PROJECT_ID}/databases/(default)/documents/users/${uid}?fields=role,displayName`;
    40→  let res;
    41→  try {
    42→    res = await fetch(url, { headers: { Authorization: `Bearer ${token}` } });
    43→  } catch (err) {
    44→    return { ok: false, err: 'Network error verifying token' };
    45→  }
    46→  if (!res.ok) return { ok: false, err: `Auth failed (${res.status})` };
    47→
    48→  const data = await res.json();
    49→  const role        = data.fields?.role?.stringValue;
    50→  const displayName = data.fields?.displayName?.stringValue || '';
    51→
    52→  if (role !== 'owner') return { ok: false, err: 'Access denied — owners only' };
    53→  return { ok: true, uid, displayName };
    54→}
