   141→  if (!sender) {
   142→    console.warn('[EmailCenter] Unknown owner:', v.displayName);
   143→    return res.status(403).json({ error: 'Unrecognized owner account' });
   144→  }
   145→
   146→  const { recipientEmail, recipientName, recipientUid, subject, message } = req.body;
   147→  if (!recipientEmail || !subject?.trim() || !message?.trim()) {
   148→    return res.status(400).json({ error: 'Missing required fields: recipientEmail, subject, message' });
   149→  }
