   151→  if (message.length > 50000) return res.status(400).json({ error: 'Message too long' });
   152→
   153→  const date = new Date().toLocaleDateString('en-US', {
   154→    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
   155→  });
   156→  const html = buildEmailHtml({
