   167→    brRes = await fetch('https://api.brevo.com/v3/smtp/email', {
   168→      method: 'POST',
   169→      headers: { 'api-key': BREVO_API_KEY, 'content-type': 'application/json' },
   170→      body: JSON.stringify({
