     2→// Rate limit store resets on cold starts (acceptable for low-volume auth emails)
     3→const rateLimitStore = new Map();
     4→
     5→/**
     6→ * Check rate limit for a key.
     7→ * @param {string} key          e.g. 'reset:1.2.3.4'
     8→ * @param {number} maxRequests  max allowed in window
     9→ * @param {number} windowMs     window in milliseconds
    10→ * @returns {{ ok: boolean, retryAfter?: number }}
    11→ */
    12→export function rateLimitCheck(key, maxRequests, windowMs) {
    13→  const now   = Date.now();
    14→  const entry = rateLimitStore.get(key) || { count: 0, start: now };
    15→
    16→  if (now - entry.start > windowMs) {
    17→    rateLimitStore.set(key, { count: 1, start: now });
    18→    return { ok: true };
    19→  }
    20→  if (entry.count >= maxRequests) {
    21→    return { ok: false, retryAfter: Math.ceil((entry.start + windowMs - now) / 1000) };
    22→  }
    23→  entry.count++;
    24→  rateLimitStore.set(key, entry);
    25→  return { ok: true };
    26→}
