.ec-header-name { font-size: 15px; font-weight: 800; color: #1e1b4b; letter-spacing:-.3px; }
.ec-header-sub  { font-size: 11px; color: #9ca3af; font-weight: 500; }
.ec-header-sender {
  display: flex; align-items: center; gap: 8px;
  background: rgba(124,58,237,.06);
  border: 1px solid rgba(124,58,237,.15);
  border-radius: 20px; padding: 5px 12px;
  white-space: nowrap;
}
.ec-sender-dot {
  width: 7px; height: 7px; border-radius: 50%;
  background: #22c55e; flex-shrink: 0;
  box-shadow: 0 0 0 2px rgba(34,197,94,.25);
}
.ec-sender-email { font-size: 12px; color: #7c3aed; font-weight: 600; }
.ec-mobile-compose-btn {
  display: none;
  align-items: center; gap: 6px;
  background: linear-gradient(135deg,#7c3aed,#a855f7);
  color: #fff; border: none; border-radius: 10px;
  padding: 7px 12px; font-size: 13px; font-weight: 700;
  cursor: pointer; white-space: nowrap;
}
@media (max-width: 900px) { .ec-mobile-compose-btn { display: flex; } }

/* ── Body ── */
.ec-body {
  flex: 1;
  display: flex;
  position: relative;
  z-index: 1;
  overflow: hidden;
  max-width: 1600px;
  width: 100%;
  margin: 0 auto;
  height: calc(100vh - 58px);
}

/* ── Sidebar ── */
.ec-sidebar {
  width: 220px;
  flex-shrink: 0;
  background: rgba(255,255,255,.6);
  backdrop-filter: blur(12px);
  border-right: 1px solid rgba(124,58,237,.1);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  transition: transform .25s ease, width .25s ease;
}
.ec-compose-btn {
  margin: 14px 12px 8px;
  background: linear-gradient(135deg,#7c3aed 0%,#a855f7 100%);
  color: #fff;
  border: none;
  border-radius: 12px;
  padding: 11px 16px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  display: flex; align-items: center; gap: 8px;
  transition: opacity .15s, box-shadow .15s;
  box-shadow: 0 4px 18px rgba(124,58,237,.28);
}
.ec-compose-btn:hover { opacity:.9; box-shadow: 0 6px 24px rgba(124,58,237,.38); }
.ec-folder-list { padding: 6px 0; }
.ec-folder-item {
  display: flex; align-items: center; gap: 10px;
  padding: 9px 14px;
  cursor: pointer;
  border-radius: 10px;
  margin: 2px 8px;
  transition: background .15s;
  color: #374151;
  font-size: 13.5px;
  font-weight: 500;
  user-select: none;
}
.ec-folder-item:hover { background: rgba(124,58,237,.07); }
.ec-folder-item.active {
  background: rgba(124,58,237,.12);
  color: #7c3aed;
  font-weight: 700;
}
.ec-folder-item.active svg { color: #7c3aed; }
.ec-folder-icon { flex-shrink: 0; color: #9ca3af; }
.ec-folder-item.active .ec-folder-icon { color: #7c3aed; }
.ec-folder-label { flex: 1; }
.ec-folder-badge {
  background: #7c3aed;
  color: #fff;
  border-radius: 10px;
  padding: 1px 7px;
  font-size: 11px;
  font-weight: 700;
  animation: ecBadgePop .25s ease;
}
.ec-sidebar-sep { height: 1px; background: rgba(124,58,237,.08); margin: 8px 14px; }

/* ── Email List Panel ── */
.ec-list-panel {
  width: 360px;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  border-right: 1px solid rgba(124,58,237,.1);
  background: rgba(255,255,255,.5);
  backdrop-filter: blur(8px);
  overflow: hidden;
}
.ec-list-header {
  padding: 12px 14px 10px;
  border-bottom: 1px solid rgba(124,58,237,.08);
  display: flex; flex-direction: column; gap: 8px;
  flex-shrink: 0;
}
.ec-list-title-row {
  display: flex; align-items: center; justify-content: space-between;
}
.ec-list-title { font-size: 14px; font-weight: 800; color: #1e1b4b; }
.ec-list-count { font-size: 11px; color: #9ca3af; font-weight: 500; }
.ec-search-wrap { position: relative; }
.ec-search-input {
  width: 100%;
  background: rgba(124,58,237,.05);
  border: 1px solid rgba(124,58,237,.15);
  border-radius: 9px;
  padding: 8px 12px 8px 34px;
  font-size: 13px;
  color: #1e1b4b;
  outline: none;
  transition: border-color .15s;
  box-sizing: border-box;
}
.ec-search-input:focus { border-color: #7c3aed; }
.ec-search-icon {
  position: absolute; left: 10px; top: 50%; transform: translateY(-50%);
  color: #9ca3af; pointer-events: none;
}
.ec-filter-row {
  display: flex; gap: 5px; flex-wrap: wrap;
}
.ec-filter-chip {
  padding: 3px 9px;
  border-radius: 20px;
  border: 1px solid rgba(124,58,237,.2);
  background: none;
  font-size: 11px; font-weight: 600;
  color: #7c3aed;
  cursor: pointer;
  transition: all .15s;
}
.ec-filter-chip.active, .ec-filter-chip:hover {
  background: #7c3aed; color: #fff; border-color: #7c3aed;
}
.ec-email-list { flex: 1; overflow-y: auto; }
.ec-email-item {
  padding: 13px 14px;
  border-bottom: 1px solid rgba(124,58,237,.06);
  cursor: pointer;
  transition: background .12s;
  position: relative;
  animation: ecFadeIn .2s ease;
}
.ec-email-item:hover { background: rgba(124,58,237,.05); }
.ec-email-item.selected { background: rgba(124,58,237,.1); }
.ec-email-item.unread .ec-item-subject { font-weight: 800; color: #1e1b4b; }
.ec-email-item.unread .ec-item-from    { font-weight: 700; color: #1e1b4b; }
.ec-item-row1 { display: flex; align-items: center; gap: 8px; margin-bottom: 4px; }
.ec-item-avatar {
  width: 32px; height: 32px; border-radius: 50%;
  background: linear-gradient(135deg,#7c3aed,#c084fc);
  display: flex; align-items: center; justify-content: center;
  color: #fff; font-size: 13px; font-weight: 700;
  flex-shrink: 0;
}
.ec-item-from { font-size: 13px; color: #374151; font-weight: 500; flex: 1; min-width: 0; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.ec-item-time { font-size: 11px; color: #9ca3af; white-space: nowrap; }
.ec-item-row2 { display: flex; align-items: flex-start; gap: 6px; }
.ec-item-subject { font-size: 13px; color: #374151; flex: 1; min-width: 0; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.ec-item-preview { font-size: 12px; color: #9ca3af; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; display: block; margin-top: 2px; }
.ec-item-indicators { display: flex; gap: 4px; align-items: center; margin-top: 4px; flex-wrap: wrap; }
.ec-item-star {
  position: absolute; right: 12px; bottom: 12px;
  background: none; border: none; cursor: pointer;
  color: #d1d5db; padding: 2px; border-radius: 4px;
  transition: color .15s;
}
.ec-item-star.starred { color: #f59e0b; }
.ec-item-star:hover { color: #f59e0b; }
.ec-unread-dot {
  width: 7px; height: 7px; border-radius: 50%; background: #7c3aed;
  position: absolute; left: 5px; top: 50%; transform: translateY(-50%);
  flex-shrink: 0;
}
.ec-status-chip {
  font-size: 10px; font-weight: 600;
  padding: 1px 6px; border-radius: 6px;
}
.ec-status-chip.replied  { background: #dbeafe; color: #2563eb; }
.ec-status-chip.forwarded { background: #dcfce7; color: #16a34a; }
.ec-status-chip.contact  { background: #fdf4ff; color: #a855f7; }
.ec-status-chip.incoming  { background: #fff7ed; color: #ea580c; }
.ec-empty-state {
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  height: 200px; color: #9ca3af; gap: 10px;
}
.ec-empty-state p { font-size: 14px; margin: 0; }
.ec-load-more-btn {
  width: 100%; padding: 12px;
  background: none; border: none; border-top: 1px solid rgba(124,58,237,.08);
  color: #7c3aed; font-size: 13px; font-weight: 600;
  cursor: pointer; transition: background .15s;
}
.ec-load-more-btn:hover { background: rgba(124,58,237,.06); }

/* ── Detail Panel ── */
.ec-detail-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: rgba(255,255,255,.45);
  backdrop-filter: blur(8px);
}
.ec-detail-empty {
  flex: 1; display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  color: #9ca3af; gap: 12px;
}
.ec-detail-empty p { font-size: 15px; color: #9ca3af; margin: 0; }
.ec-detail-content { flex: 1; display: flex; flex-direction: column; overflow: hidden; animation: ecFadeIn .2s ease; }
.ec-detail-toolbar {
  display: flex; align-items: center; gap: 6px;
  padding: 10px 16px;
  border-bottom: 1px solid rgba(124,58,237,.08);
  flex-shrink: 0;
  flex-wrap: wrap;
}
.ec-tool-btn {
  display: flex; align-items: center; gap: 5px;
  background: none; border: 1px solid rgba(124,58,237,.15);
  border-radius: 8px; padding: 6px 10px;
  font-size: 12px; font-weight: 600; color: #374151;
  cursor: pointer; transition: all .15s; white-space: nowrap;
}
.ec-tool-btn:hover { background: rgba(124,58,237,.06); border-color: #7c3aed; color: #7c3aed; }
.ec-tool-btn.primary { background: rgba(124,58,237,.1); border-color: #7c3aed; color: #7c3aed; }
.ec-tool-btn.danger  { color: #ef4444; border-color: rgba(239,68,68,.3); }
.ec-tool-btn.danger:hover { background: rgba(239,68,68,.06); }
.ec-tool-btn.star-active { color: #f59e0b; border-color: rgba(245,158,11,.3); }
.ec-tool-sep { width: 1px; height: 20px; background: rgba(124,58,237,.12); margin: 0 2px; }
.ec-detail-scroll { flex: 1; overflow-y: auto; padding: 20px 24px; }
.ec-detail-subject {
  font-size: 20px; font-weight: 800; color: #1e1b4b;
  letter-spacing: -.4px; margin-bottom: 14px; line-height: 1.3;
}
.ec-detail-meta {
  display: flex; flex-direction: column; gap: 6px;
  background: rgba(124,58,237,.04);
  border: 1px solid rgba(124,58,237,.1);
  border-radius: 12px; padding: 14px 16px;
  margin-bottom: 20px;
}
.ec-meta-row { display: flex; gap: 8px; font-size: 13px; }
.ec-meta-label { color: #9ca3af; font-weight: 600; width: 42px; flex-shrink: 0; }
.ec-meta-val { color: #374151; }
.ec-meta-email { color: #7c3aed; }
.ec-detail-body {
  font-size: 15px; color: #374151; line-height: 1.85;
  white-space: pre-wrap; word-break: break-word;
}
.ec-detail-body-html {
  font-size: 15px; line-height: 1.8; color: #374151;
}
.ec-detail-body-html a { color: #7c3aed; }
.ec-detail-body-html img { max-width: 100%; border-radius: 8px; }
.ec-thread-sep {
  display: flex; align-items: center; gap: 10px;
  margin: 24px 0;
  color: #9ca3af; font-size: 12px; font-weight: 600;
}
.ec-thread-sep::before, .ec-thread-sep::after {
  content: ''; flex: 1; height: 1px; background: rgba(124,58,237,.1);
}
.ec-thread-item {
  background: rgba(255,255,255,.7);
  border: 1px solid rgba(124,58,237,.1);
  border-radius: 12px; padding: 16px 18px;
  margin-bottom: 12px; animation: ecFadeIn .2s ease;
}
.ec-thread-header {
  display: flex; align-items: center; gap: 10px;
  margin-bottom: 10px;
}
.ec-thread-avatar {
  width: 28px; height: 28px; border-radius: 50%;
  background: linear-gradient(135deg,#7c3aed,#c084fc);
  display: flex; align-items: center; justify-content: center;
  color: #fff; font-size: 11px; font-weight: 700; flex-shrink: 0;
}
.ec-thread-from { font-size: 13px; font-weight: 700; color: #1e1b4b; }
.ec-thread-time { font-size: 11px; color: #9ca3af; margin-left: auto; }
.ec-thread-body { font-size: 14px; color: #374151; line-height: 1.7; white-space: pre-wrap; }

/* ── Reply / Inline Compose Area ── */
.ec-reply-area {
  border-top: 1px solid rgba(124,58,237,.1);
  padding: 16px 24px;
  background: rgba(255,255,255,.6);
  flex-shrink: 0;
}
.ec-reply-header {
  font-size: 12px; font-weight: 700; color: #7c3aed;
  margin-bottom: 10px;
  text-transform: uppercase; letter-spacing: .06em;
}
.ec-reply-textarea {
  width: 100%; min-height: 100px; max-height: 240px;
  background: rgba(124,58,237,.04);
  border: 1px solid rgba(124,58,237,.2);
  border-radius: 10px; padding: 12px 14px;
  font-size: 14px; color: #1e1b4b;
  resize: vertical; outline: none;
  transition: border-color .15s;
  font-family: inherit;
  box-sizing: border-box;
}
.ec-reply-textarea:focus { border-color: #7c3aed; }
.ec-reply-actions {
  display: flex; align-items: center; gap: 8px; margin-top: 10px;
}
.ec-send-btn {
  display: flex; align-items: center; gap: 6px;
  background: linear-gradient(135deg,#7c3aed,#a855f7);
  color: #fff; border: none; border-radius: 10px;
  padding: 9px 18px; font-size: 13px; font-weight: 700;
  cursor: pointer; transition: opacity .15s, box-shadow .15s;
  box-shadow: 0 4px 14px rgba(124,58,237,.3);
}
.ec-send-btn:hover:not(:disabled) { opacity:.9; }
.ec-send-btn:disabled { opacity:.5; cursor:not-allowed; }
.ec-cancel-reply-btn {
  background: none; border: 1px solid rgba(124,58,237,.2);
  border-radius: 9px; padding: 8px 14px;
  font-size: 13px; font-weight: 600; color: #6b7280;
  cursor: pointer; transition: background .15s;
}
.ec-cancel-reply-btn:hover { background: rgba(0,0,0,.04); }

/* ── Compose Modal ── */
.ec-modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,.35);
  backdrop-filter: blur(6px);
  z-index: 200;
  display: flex; align-items: flex-end; justify-content: flex-end;
  padding: 0 20px 20px 0;
  animation: ecFadeIn .18s ease;
}
.ec-modal-card {
  background: rgba(255,255,255,.96);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(124,58,237,.15);
  border-radius: 18px;
  width: 100%;
  max-width: 580px;
  max-height: 88vh;
  display: flex;
  flex-direction: column;
  box-shadow: 0 16px 64px rgba(124,58,237,.2);
  animation: ecFadeIn .2s ease;
}
.ec-modal-header {
  display: flex; align-items: center; justify-content: space-between;
  padding: 16px 20px 12px;
  border-bottom: 1px solid rgba(124,58,237,.1);
  flex-shrink: 0;
}
.ec-modal-title {
  font-size: 14px; font-weight: 800; color: #1e1b4b;
  display: flex; align-items: center; gap: 8px;
}
.ec-modal-close {
  width: 28px; height: 28px; border-radius: 8px;
  background: none; border: none; cursor: pointer;
  color: #9ca3af; display: flex; align-items: center; justify-content: center;
  transition: all .15s;
}
.ec-modal-close:hover { background: rgba(0,0,0,.06); color: #374151; }
.ec-modal-body { flex: 1; overflow-y: auto; padding: 16px 20px; display: flex; flex-direction: column; gap: 12px; }
.ec-field { display: flex; flex-direction: column; gap: 5px; }
.ec-field-label { font-size: 11px; font-weight: 700; color: #9ca3af; text-transform: uppercase; letter-spacing: .06em; }
.ec-from-display {
  display: flex; align-items: center; gap: 8px;
  background: rgba(124,58,237,.06); border: 1px solid rgba(124,58,237,.12);
  border-radius: 9px; padding: 9px 12px;
  font-size: 13px; color: #374151;
}
.ec-from-name  { font-weight: 700; color: #1e1b4b; }
.ec-from-sep   { color: #d1d5db; }
.ec-from-email { color: #7c3aed; font-weight: 600; }
.ec-auto-chip  { background: #dbeafe; color: #2563eb; font-size: 10px; font-weight: 700; border-radius: 6px; padding: 2px 6px; }
.ec-recipient-wrap { position: relative; }
.ec-recipient-input {
  width: 100%;
  background: rgba(124,58,237,.04); border: 1px solid rgba(124,58,237,.15);
  border-radius: 9px; padding: 9px 12px;
  font-size: 13px; color: #1e1b4b; outline: none;
  transition: border-color .15s; box-sizing: border-box;
}
.ec-recipient-input:focus { border-color: #7c3aed; background: rgba(124,58,237,.06); }
.ec-selected-recipient {
  display: flex; align-items: center; gap: 8px;
  background: rgba(124,58,237,.06); border: 1px solid rgba(124,58,237,.15);
  border-radius: 9px; padding: 8px 12px;
}
.ec-selected-name  { font-size: 13px; font-weight: 700; color: #1e1b4b; flex: 1; }
.ec-selected-email { font-size: 12px; color: #7c3aed; }
.ec-clear-btn {
  width: 20px; height: 20px; border-radius: 50%;
  background: rgba(0,0,0,.08); border: none;
  cursor: pointer; color: #6b7280; font-size: 13px;
  display: flex; align-items: center; justify-content: center;
  transition: background .15s;
}
.ec-clear-btn:hover { background: rgba(0,0,0,.14); }
.ec-dropdown {
  position: absolute; top: calc(100% + 4px); left: 0; right: 0;
  background: #fff; border: 1px solid rgba(124,58,237,.2);
  border-radius: 10px; box-shadow: 0 8px 32px rgba(0,0,0,.12);
  z-index: 50; max-height: 220px; overflow-y: auto;
}
.ec-dropdown-item {
  display: flex; align-items: center; gap: 10px;
  padding: 10px 14px; cursor: pointer; transition: background .12s;
}
.ec-dropdown-item:hover { background: rgba(124,58,237,.06); }
.ec-dd-avatar {
  width: 28px; height: 28px; border-radius: 50%;
  background: linear-gradient(135deg,#7c3aed,#c084fc);
  display: flex; align-items: center; justify-content: center;
  color: #fff; font-size: 11px; font-weight: 700; flex-shrink: 0;
}
.ec-dd-name  { font-size: 13px; font-weight: 700; color: #1e1b4b; }
.ec-dd-email { font-size: 11px; color: #9ca3af; }
.ec-dd-no-results { padding: 14px; text-align: center; color: #9ca3af; font-size: 13px; }
.ec-input, .ec-textarea {
  width: 100%; background: rgba(124,58,237,.04); border: 1px solid rgba(124,58,237,.15);
  border-radius: 9px; padding: 9px 12px; font-size: 13px;
  color: #1e1b4b; outline: none; transition: border-color .15s;
  font-family: inherit; box-sizing: border-box;
}
.ec-input:focus, .ec-textarea:focus { border-color: #7c3aed; }
.ec-textarea { min-height: 180px; resize: vertical; line-height: 1.6; }
.ec-preview-box {
  background: #f9fafb; border: 1px solid rgba(124,58,237,.1);
  border-radius: 10px; padding: 16px; font-size: 14px;
  color: #374151; line-height: 1.75; white-space: pre-wrap;
  max-height: 180px; overflow-y: auto;
}
.ec-modal-footer {
  display: flex; align-items: center; gap: 8px;
  padding: 12px 20px 16px;
  border-top: 1px solid rgba(124,58,237,.08);
  flex-shrink: 0;
}
.ec-preview-toggle-btn {
  background: none; border: 1px solid rgba(124,58,237,.2);
  border-radius: 9px; padding: 8px 13px;
  font-size: 12px; font-weight: 600; color: #7c3aed;
  cursor: pointer; transition: all .15s;
}
.ec-preview-toggle-btn:hover { background: rgba(124,58,237,.06); }
.ec-draft-btn {
  background: none; border: 1px solid rgba(124,58,237,.2);
  border-radius: 9px; padding: 8px 13px;
  font-size: 12px; font-weight: 600; color: #6b7280;
  cursor: pointer; transition: all .15s; margin-left: auto;
}
.ec-draft-btn:hover { background: rgba(0,0,0,.04); }

/* ── Forward Modal ── */
.ec-forward-modal {
  position: fixed; inset: 0;
  background: rgba(0,0,0,.35); backdrop-filter: blur(6px);
  z-index: 200; display: flex; align-items: center; justify-content: center; padding: 20px;
  animation: ecFadeIn .18s ease;
}

/* ── Responsive ── */
@media (max-width: 1100px) {
  .ec-list-panel { width: 300px; }
}
@media (max-width: 900px) {
  .ec-sidebar { width: 200px; }
  .ec-list-panel { width: 260px; }
  .ec-header-sender { display: none; }
}
@media (max-width: 700px) {
  .ec-sidebar { position: absolute; z-index: 20; height: 100%; left: 0; transform: translateX(-100%); box-shadow: 4px 0 24px rgba(0,0,0,.12); }
  .ec-sidebar.mobile-open { transform: translateX(0); }
  .ec-list-panel { width: 100%; }
  .ec-detail-panel { position: absolute; inset: 0; z-index: 10; background: rgba(255,255,255,.97); display: none; }
  .ec-detail-panel.mobile-open { display: flex; }
  .ec-modal-overlay { padding: 10px; align-items: center; justify-content: center; }
  .ec-modal-card { max-height: 95vh; }
  .ec-detail-scroll { padding: 14px 16px; }
}

/* ── Scrollbar ── */
.ec-email-list::-webkit-scrollbar,
.ec-detail-scroll::-webkit-scrollbar,
.ec-modal-body::-webkit-scrollbar { width: 4px; }
.ec-email-list::-webkit-scrollbar-thumb,
.ec-detail-scroll::-webkit-scrollbar-thumb,
.ec-modal-body::-webkit-scrollbar-thumb { background: rgba(124,58,237,.2); border-radius: 4px; }

/* ── Dark mode ── */
@media (prefers-color-scheme: dark) {
  .ec-root { background: linear-gradient(150deg,#0d0814 0%,#120920 40%,#0f0b1a 100%); }
  .ec-header { background: rgba(15,11,26,.8); border-bottom-color: rgba(124,58,237,.2); }
